/**
 * amplituhedron-wire — residual positional-dictionary tests.
 *
 * Validates the `GNOSIS_RESIDUAL_DICT` env-var loader hooked into the
 * f32 → bw_codec → wire path:
 *
 *   1. With a synthetic BWDC dictionary in scope, encode raises
 *      `BW_VERSION_POSDICT_FLAG` (0x20) on the inner bw_codec version byte.
 *   2. With no env var, encode emits plain bw (version byte 0x01).
 *   3. Round-trip through encode + decode with a dict loaded is byte-exact.
 *   4. `_resetDictCache()` lets the loader pick up a fresh env var.
 */

import { mkdtempSync, writeFileSync } from 'node:fs';
import { tmpdir } from 'node:os';
import { join } from 'node:path';

import { afterEach, beforeEach, describe, expect, it } from 'vitest';

import {
  _resetDictCache,
  decodeCaptureRequest,
  encodeCaptureRequest,
} from '../amplituhedron-wire';

/** Build a BWDC dictionary file (header + entries) at a temp path. */
function writeBwdcDict(entries: Uint8Array[]): string {
  if (entries.length === 0) {
    throw new Error('writeBwdcDict: need at least one entry');
  }
  const entryLen = entries[0]!.length;
  for (const e of entries) {
    if (e.length !== entryLen) {
      throw new Error('writeBwdcDict: ragged entries not supported by the BWDC v1 layout');
    }
  }
  const total = 16 + entries.length * entryLen;
  const buf = new Uint8Array(total);
  // magic 'BWDC'
  buf[0] = 0x42;
  buf[1] = 0x57;
  buf[2] = 0x44;
  buf[3] = 0x43;
  const dv = new DataView(buf.buffer, buf.byteOffset, buf.byteLength);
  dv.setUint32(4, 1, true); // version
  dv.setUint32(8, entries.length, true); // count
  dv.setUint32(12, entryLen, true); // entry_len
  for (let i = 0; i < entries.length; i++) {
    buf.set(entries[i]!, 16 + i * entryLen);
  }
  const dir = mkdtempSync(join(tmpdir(), 'amph-wire-bwdc-'));
  const path = join(dir, 'residual.bwdict');
  writeFileSync(path, buf);
  return path;
}

/**
 * The BWAH envelope wraps a bw_codec blob whose first byte is the magic
 * 'B' (0x42). The inner version byte sits four bytes deeper — bw_codec's
 * `BW_MAGIC` is 4 B and version is byte 4. The capture envelope adds a
 * 22-byte header (REPLAY 10 B + CAPTURE_EXTRA 16 B = 26 B by the wire
 * layout above), so the bw_codec version byte is at offset 26 + 4 = 30.
 */
function bwVersionByteFromCapture(wire: Uint8Array): number {
  // BWAH header is MAGIC(4) + VERSION(1) + FLAGS(1) + tail_len(4) +
  // kv_slab_len(4) + prefix_hash(8) + prefix_len(4) + layer_lo(2) +
  // layer_hi(2) = 30 bytes. The bw_codec blob starts there with its own
  // 4-byte magic, so its version byte is offset 30 + 4 = 34.
  const BWAH_HEADER = 30;
  const BW_MAGIC_LEN = 4;
  return wire[BWAH_HEADER + BW_MAGIC_LEN]!;
}

const SAMPLE_RESIDUAL = (): Float32Array => {
  // Deterministic, non-zero samples so the f32 → LE bytes are well-defined.
  const out = new Float32Array(8);
  for (let i = 0; i < out.length; i++) {
    out[i] = (i + 1) * 0.125;
  }
  return out;
};

const CAPTURE_ARGS = () => ({
  prefixHash: '12345678901234567890',
  prefixLen: 7,
  layerLo: 0,
  layerHi: 3,
  tailResidual: SAMPLE_RESIDUAL(),
});

describe('amplituhedron-wire residual posdict integration', () => {
  const ENV_KEY = 'GNOSIS_RESIDUAL_DICT';
  let savedEnv: string | undefined;

  beforeEach(() => {
    savedEnv = process.env[ENV_KEY];
    delete process.env[ENV_KEY];
    _resetDictCache();
  });

  afterEach(() => {
    if (savedEnv === undefined) {
      delete process.env[ENV_KEY];
    } else {
      process.env[ENV_KEY] = savedEnv;
    }
    _resetDictCache();
  });

  it('encode_with_residual_dict_uses_posdict', () => {
    // A 32-byte dictionary entry won't actually match the residual bytes
    // (which is fine — what we're asserting is the version-byte flag, not
    // a compression ratio).
    const path = writeBwdcDict([new Uint8Array(32).fill(0xab)]);
    process.env[ENV_KEY] = path;
    _resetDictCache();

    const wire = encodeCaptureRequest(CAPTURE_ARGS());
    const versionByte = bwVersionByteFromCapture(wire);
    expect(versionByte & 0x20).toBe(0x20);
  });

  it('encode_without_residual_dict_uses_plain_bw_codec', () => {
    // No env var set — loader caches null, encode goes through plain bw.
    const wire = encodeCaptureRequest(CAPTURE_ARGS());
    const versionByte = bwVersionByteFromCapture(wire);
    expect(versionByte).toBe(0x01);
  });

  it('decode_handles_posdict_payload_with_loaded_dict', () => {
    const path = writeBwdcDict([new Uint8Array(16).fill(0x7e)]);
    process.env[ENV_KEY] = path;
    _resetDictCache();

    const args = CAPTURE_ARGS();
    const wire = encodeCaptureRequest(args);
    const decoded = decodeCaptureRequest(wire);

    expect(decoded.prefixHash).toBe(args.prefixHash);
    expect(decoded.prefixLen).toBe(args.prefixLen);
    expect(decoded.layerLo).toBe(args.layerLo);
    expect(decoded.layerHi).toBe(args.layerHi);
    expect(decoded.tailResidual.length).toBe(args.tailResidual.length);
    for (let i = 0; i < args.tailResidual.length; i++) {
      expect(decoded.tailResidual[i]).toBe(args.tailResidual[i]);
    }
  });

  it('resetDictCache_clears_cached_entries', () => {
    const pathA = writeBwdcDict([new Uint8Array(8).fill(0x11)]);
    const pathB = writeBwdcDict([new Uint8Array(8).fill(0x22)]);

    process.env[ENV_KEY] = pathA;
    _resetDictCache();
    const wireA = encodeCaptureRequest(CAPTURE_ARGS());
    const verA = bwVersionByteFromCapture(wireA);
    expect(verA & 0x20).toBe(0x20);

    // Flip env without resetting → loader returns cached value from pathA,
    // so the version byte still has the flag (this proves caching works).
    process.env[ENV_KEY] = pathB;
    const wireStillCached = encodeCaptureRequest(CAPTURE_ARGS());
    expect(bwVersionByteFromCapture(wireStillCached) & 0x20).toBe(0x20);

    // Reset → loader picks up pathB on next call (still a valid dict, so
    // the flag stays set; the contract under test is that the reset
    // actually re-reads the env).
    _resetDictCache();
    const wireB = encodeCaptureRequest(CAPTURE_ARGS());
    expect(bwVersionByteFromCapture(wireB) & 0x20).toBe(0x20);

    // And finally, after clearing the env + reset, plain bw is used.
    delete process.env[ENV_KEY];
    _resetDictCache();
    const wirePlain = encodeCaptureRequest(CAPTURE_ARGS());
    expect(bwVersionByteFromCapture(wirePlain)).toBe(0x01);
  });
});
